def loss(x):
    return (x - 3) ** 2

def gradient(x):
    return 2 * (x - 3)

x = 8.0          # start far from the answer
lr = 0.1         # learning rate

for step in range(10):
    grad = gradient(x)
    x = x - lr * grad   # step downhill
    print(f"Step {step+1}: x = {x:.4f}, loss = {loss(x):.4f}")

