def loss(x):
    return (x - 7) ** 2

def gradient(x):
    return 2 * (x - 7)

x = 0.0
lr = 0.15

for step in range(1, 26):
    x -= lr * gradient(x)
    if step % 5 == 0:
        print(f"Step {step:2d} | x = {x:.4f} | loss = {loss(x):.4f}")

